// Arma tabla HTML legible. Solo campos minimos, sin datos sensibles.
// Escape HTML basico para todo valor textual insertado.
function esc(v) {
  if (v === null || v === undefined) return '';
  return String(v)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}
const fmt = n => Number(n).toLocaleString('es-AR');
// L2 SIEMPRE devuelve >=1 fila (incluye centinela). Filtramos la centinela.
const all = items.map(i => i.json);
const rows = all.filter(r => r.es_centinela === false || r.es_centinela === 'false');
let html = `<h2>Reservas con saldo pendiente</h2>`;
if (!rows.length) {
  html += '<p>No hay reservas con saldo pendiente.</p>';
} else {
  html += '<table border=1 cellpadding=6 cellspacing=0>';
  html += '<tr><th>#ID</th><th>Cabaña</th><th>Check-in</th><th>Check-out</th><th>Saldo</th></tr>';
  for (const r of rows) {
    html += `<tr><td><b>#${esc(r.id_reserva)}</b></td><td>${esc(r.cabana)}</td>`;
    html += `<td>${esc(r.fecha_checkin)}</td><td>${esc(r.fecha_checkout)}</td>`;
    html += `<td>$${esc(fmt(r.saldo_real))}</td></tr>`;
  }
  html += '</table>';
}
return [{ json: { html } }];
